import type { Agent } from '../data/agents'

interface Props {
  agent: Agent
  isSelected: boolean
  onClick: () => void
}

const colorMap: Record<string, { border: string; bg: string; text: string }> = {
  cmo: { border: 'border-blue-500', bg: 'bg-blue-500/10', text: 'text-blue-400' },
  planner: { border: 'border-violet-500', bg: 'bg-violet-500/10', text: 'text-violet-400' },
  researcher: { border: 'border-emerald-500', bg: 'bg-emerald-500/10', text: 'text-emerald-400' },
  cso: { border: 'border-amber-500', bg: 'bg-amber-500/10', text: 'text-amber-400' },
  cto: { border: 'border-red-500', bg: 'bg-red-500/10', text: 'text-red-400' },
}

export default function AgentCard({ agent, isSelected, onClick }: Props) {
  const c = colorMap[agent.id] ?? colorMap.cmo

  return (
    <button
      onClick={onClick}
      className={`text-left w-full rounded-xl border-2 p-5 transition-all duration-200 cursor-pointer
        ${isSelected ? `${c.border} ${c.bg} scale-[1.02] shadow-lg` : 'border-slate-700/50 bg-slate-800/50 hover:border-slate-600 hover:bg-slate-800'}
      `}
    >
      <div className="flex items-center gap-3 mb-3">
        <span className="text-3xl">{agent.emoji}</span>
        <div>
          <h3 className={`font-bold text-lg ${c.text}`}>{agent.title}</h3>
          <p className="text-xs text-slate-500">{agent.titleEn}</p>
        </div>
      </div>

      <ul className="space-y-1 mb-4">
        {agent.responsibilities.map((r) => (
          <li key={r} className="text-sm text-slate-300 flex items-start gap-2">
            <span className="text-slate-600 mt-0.5">•</span>
            {r}
          </li>
        ))}
      </ul>

      <div className="flex flex-wrap gap-1.5">
        {agent.collaborators.map((col) => (
          <span
            key={col}
            className="text-[10px] px-2 py-0.5 rounded-full bg-slate-700/50 text-slate-400"
          >
            {col}
          </span>
        ))}
      </div>
    </button>
  )
}

