import { useState, useEffect } from 'react'

interface DailyOutputData {
  date: string
  content: string | null
  found: boolean
}

function renderMarkdown(md: string): string {
  return md
    .replace(/^### (.+)$/gm, '<h3 class="text-sm font-bold text-slate-200 mt-4 mb-1">$1</h3>')
    .replace(/^## (.+)$/gm, '<h2 class="text-base font-bold text-white mt-5 mb-2 border-b border-slate-700 pb-1">$1</h2>')
    .replace(/^# (.+)$/gm, '<h1 class="text-lg font-bold text-white mt-4 mb-2">$1</h1>')
    .replace(/\*\*(.+?)\*\*/g, '<strong class="text-white font-semibold">$1</strong>')
    .replace(/🔴/g, '<span class="text-red-400">🔴</span>')
    .replace(/🟡/g, '<span class="text-yellow-400">🟡</span>')
    .replace(/🟢/g, '<span class="text-green-400">🟢</span>')
    .replace(/^- (.+)$/gm, '<li class="text-[11px] text-slate-300 ml-3 list-disc">$1</li>')
    .replace(/^\d+\. (.+)$/gm, '<li class="text-[11px] text-slate-300 ml-3 list-decimal">$1</li>')
    .replace(/^\|(.+)\|$/gm, (_match, row) => {
      const cells = row.split('|').map((c: string) => c.trim())
      const isHeader = cells.some((c: string) => c.match(/^-+$/))
      if (isHeader) return ''
      const tag = 'td'
      return '<tr>' + cells.map((c: string) =>
        `<${tag} class="text-[11px] text-slate-300 px-2 py-1 border border-slate-700">${c}</${tag}>`
      ).join('') + '</tr>'
    })
    .replace(/(<tr>.*<\/tr>\n?)+/gs, (m) =>
      `<table class="w-full text-left border-collapse my-2">${m}</table>`
    )
    .replace(/\n{2,}/g, '<br class="my-1"/>')
    .replace(/^(?!<[hltb])(.+)$/gm, '<p class="text-[11px] text-slate-400">$1</p>')
}

export default function DailyReview() {
  const [data, setData] = useState<DailyOutputData | null>(null)
  const [expanded, setExpanded] = useState(false)

  useEffect(() => {
    const fetch_ = () => {
      fetch(`/api/daily-output?t=${Date.now()}`)
        .then(r => r.json())
        .then(setData)
        .catch(() => {})
    }
    fetch_()
    const id = setInterval(fetch_, 30000)
    return () => clearInterval(id)
  }, [])

  const today = new Date().toISOString().split('T')[0]
  const isToday = data?.date === today

  return (
    <div className="rounded-xl border border-slate-700/50 bg-slate-800/30 p-5">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <span className="text-base">📋</span>
          <h3 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">
            日次レビュー
          </h3>
          {data && (
            <span className={`text-[10px] px-2 py-0.5 rounded-full font-medium ${
              isToday
                ? 'bg-green-500/20 text-green-400'
                : 'bg-yellow-500/20 text-yellow-400'
            }`}>
              {data.date}
            </span>
          )}
        </div>
        {data?.content && (
          <button
            onClick={() => setExpanded(!expanded)}
            className="text-[10px] px-2 py-1 rounded bg-slate-700 text-slate-300 hover:bg-slate-600 transition-colors"
          >
            {expanded ? '折りたたむ' : '展開する'}
          </button>
        )}
      </div>

      {!data && (
        <p className="text-xs text-slate-500 animate-pulse">読み込み中...</p>
      )}

      {data && !data.content && (
        <p className="text-xs text-slate-500">本日の日次レビューはまだ生成されていません。</p>
      )}

      {data?.content && !expanded && (
        <div className="space-y-2">
          {/* Show just the highlights section */}
          {data.content.split('\n').slice(0, 20).map((line, i) => {
            if (line.startsWith('## ') || line.startsWith('# ')) {
              return (
                <p key={i} className="text-xs font-semibold text-slate-300">
                  {line.replace(/^#+\s/, '')}
                </p>
              )
            }
            if (line.startsWith('- ') || line.match(/^\d+\./)) {
              return (
                <p key={i} className="text-[11px] text-slate-400 ml-2">
                  {line}
                </p>
              )
            }
            if (line.trim() && !line.startsWith('|') && !line.startsWith('<!--')) {
              return (
                <p key={i} className="text-[11px] text-slate-400">
                  {line}
                </p>
              )
            }
            return null
          })}
          <button
            onClick={() => setExpanded(true)}
            className="text-[10px] text-blue-400 hover:text-blue-300 mt-1"
          >
            続きを読む →
          </button>
        </div>
      )}

      {data?.content && expanded && (
        <div
          className="overflow-y-auto max-h-[600px] text-[11px] space-y-1 pr-1"
          dangerouslySetInnerHTML={{ __html: renderMarkdown(data.content) }}
        />
      )}

      {!isToday && data?.content && (
        <p className="text-[10px] text-yellow-500 mt-3">
          ※ 本日（{today}）のレビューはまだ生成されていません。直近のレビューを表示中。
        </p>
      )}
    </div>
  )
}

