import { useState, useEffect } from 'react'

interface SourceData {
  content: string | null
  found: boolean
}

interface ParsedSource {
  id: string
  name: string
  query: string
  purpose: string
}

interface SourceSection {
  title: string
  sources: ParsedSource[]
}

function parseSources(md: string): SourceSection[] {
  const sections: SourceSection[] = []
  let currentTitle = ''
  let currentSources: ParsedSource[] = []

  for (const line of md.split('\n')) {
    const headerMatch = line.match(/^### (.+)/)
    if (headerMatch) {
      if (currentTitle && currentSources.length > 0) {
        sections.push({ title: currentTitle, sources: currentSources })
      }
      currentTitle = headerMatch[1]
      currentSources = []
      continue
    }
    const rowMatch = line.match(/^\|\s*(\d+)\s*\|\s*(.+?)\s*\|\s*(.+?)\s*\|\s*(.+?)\s*\|$/)
    if (rowMatch) {
      currentSources.push({
        id: rowMatch[1],
        name: rowMatch[2].trim(),
        query: rowMatch[3].trim(),
        purpose: rowMatch[4].trim(),
      })
    }
  }
  if (currentTitle && currentSources.length > 0) {
    sections.push({ title: currentTitle, sources: currentSources })
  }
  return sections
}

