import { useState, useEffect } from 'react'

interface ReportData {
  content: string | null
  found: boolean
  lastModified: string | null
}

interface ParsedMetrics {
  shopifySales?: string
  shopifyUnits?: string
  cvr?: string
  topFunnelDrop?: string
  roas?: string
  scrollDepth?: string
  topSuggestion?: string
  date?: string
}

function parseMetrics(md: string): ParsedMetrics {
  const metrics: ParsedMetrics = {}

  const dateMatch = md.match(/##\s+【(\d{4}-\d{2}-\d{2})\s*Web Analyst/)
  if (dateMatch) metrics.date = dateMatch[1]

  const salesMatch = md.match(/Shopify当月売上[：:]\s*([^\n]+)/)
  if (salesMatch) metrics.shopifySales = salesMatch[1].trim()

  const cvrMatch = md.match(/自社EC CVR[：:]\s*([^\n（(]+)/)
  if (cvrMatch) metrics.cvr = cvrMatch[1].trim()

  const funnelMatch = md.match(/最大離脱ポイント[：:]\s*([^\n]+)/)
  if (funnelMatch) metrics.topFunnelDrop = funnelMatch[1].trim()

  const roasMatch = md.match(/ROAS[：:]\s*([^\n（(]+)/)
  if (roasMatch) metrics.roas = roasMatch[1].trim()

  const scrollMatch = md.match(/スクロール深度[：:]\s*([^\n]+)/)
  if (scrollMatch) metrics.scrollDepth = scrollMatch[1].trim()

  const suggestionMatch = md.match(/内部データが示す最優先改善箇所[：:]\s*([^\n]+)/)
  if (suggestionMatch) metrics.topSuggestion = suggestionMatch[1].trim()

  return metrics
}

function getLatestSection(md: string): string {
  const sections = md.split(/(?=##\s+【\d{4}-\d{2}-\d{2})/g)
  return sections[sections.length - 1] || md
}

function renderMarkdown(md: string): string {
  return md
    .replace(/^### (.+)$/gm, '<h3 class="text-xs font-bold text-slate-200 mt-3 mb-1">$1</h3>')
    .replace(/^## (.+)$/gm, '<h2 class="text-sm font-bold text-white mt-4 mb-2 border-b border-slate-700 pb-1">$2</h2>'.replace('$2', '$1'))
    .replace(/\*\*(.+?)\*\*/g, '<strong class="text-white font-semibold">$1</strong>')
    .replace(/^- (.+)$/gm, '<li class="text-[11px] text-slate-300 ml-3 list-disc">$1</li>')
    .replace(/^\|(.+)\|$/gm, (_match, row) => {
      const cells = row.split('|').map((c: string) => c.trim())
      if (cells.some((c: string) => c.match(/^-+$/))) return ''
      return '<tr>' + cells.map((c: string) =>
        `<td class="text-[11px] text-slate-300 px-2 py-1 border border-slate-700">${c}</td>`
      ).join('') + '</tr>'
    })
    .replace(/(<tr>.*<\/tr>\n?)+/gs, (m) =>
      `<table class="w-full text-left border-collapse my-2">${m}</table>`
    )
    .replace(/\n{2,}/g, '<br class="my-1"/>')
    .replace(/^(?!<[hltb])(.+)$/gm, '<p class="text-[11px] text-slate-400">$1</p>')
}

